BEGIN
  p_Name_8b403d4f := 'Realtime';
  p_Description_8b403d4f := 'Real-time agent type — a first-class peer of Loop and Flow that drives a streaming, full-duplex BaseRealtimeModel session (voice today, video later) instead of an iterative reasoning loop. The model owns the listen-reason-speak loop; the agent delegates real work back to async (Loop/Flow) agents via tool calls. The first agent of this type is the Voice Co-Agent, which voices on behalf of any target agent. The system prompt is per-agent (assembled at session start), so there is no type-level SystemPromptID.';
  p_IsActive_8b403d4f := TRUE;
  p_DriverClass_8b403d4f := 'RealtimeAgentType';
  p_UIFormSectionExpandedByDefault_8b403d4f := FALSE;
  p_ConfigSchema_8b403d4f := '{"$schema":"http://json-schema.org/draft-07/schema#","title":"Realtime Co-Agent TypeConfiguration","description":"Configuration payload for agents of the Realtime type — the agent''s realtime profile. Effective config = AIAgentType.DefaultConfiguration <- AIAgent.TypeConfiguration <- runtime overrides (later layers win per key, deep-merged).","type":"object","additionalProperties":false,"properties":{"realtime":{"type":"object","additionalProperties":false,"properties":{"modelPreference":{"type":"string","description":"Preferred realtime AI model (name or ID). Used unless an authorized runtime override supplies a different model."},"voice":{"type":"object","additionalProperties":false,"properties":{"default":{"type":"object","additionalProperties":false,"properties":{"tone":{"type":"string","description":"Spoken tone folded into the session system prompt (e.g. ''warm, unhurried'')."},"speakingStyle":{"type":"string","description":"Speaking style folded into the session system prompt (e.g. ''concise, plain language'')."}}},"providers":{"type":"object","description":"Per-provider voice settings, keyed by provider key (openai, gemini, elevenlabs, assemblyai).","additionalProperties":{"type":"object","additionalProperties":false,"properties":{"voice":{"type":"string","description":"Provider voice name/preset (e.g. ''alloy'')."},"voiceId":{"type":"string","description":"Provider voice identifier where voices are ID-addressed (e.g. ElevenLabs)."}}}}}},"allowUserModelOverride":{"type":"boolean","description":"When false, even authorized users cannot override the model at runtime for sessions fronted by this agent."},"narration":{"type":"object","additionalProperties":false,"properties":{"paceMs":{"type":"number","description":"Minimum milliseconds between spoken progress narrations while delegated work runs."}}}}}}}';
  p_DefaultConfiguration_8b403d4f := '{"realtime":{"allowUserModelOverride":true,"narration":{"paceMs":8000},"turnTaking":{"moderator":{"promptId":"0B4C7759-554B-4CE5-81AE-ACB43B71BD44","contextWindowTurns":30,"maxCharsPerTurn":240,"maxConsecutiveAgentOnlyTurns":null,"timeoutMs":800,"onError":"silent","prestageOnAgentSpeech":true}}}}';
  p_ID_8b403d4f := '29CA70B4-A097-474F-A5CE-3522ADD6407F';
